const defaultState = {
  phase: "investigation",
  found: [],
  missing: ["method", "time", "route", "motive"],
  next_scene: "study_lock",
  recommended_action: { kind: "inspect_study_lock", target: "study_lock" },
  last_action: "start",
  new_badges: [],
  response_mode: "opening"
};
const existing = board.getVar("case_progress_state") || {};
const state = Object.assign({}, defaultState, existing || {});
state.found = Array.isArray(state.found) ? state.found : [];
state.missing = Array.isArray(state.missing) ? state.missing : defaultState.missing;
state.new_badges = [];
board.setVar("case_progress_state", state);
board.setVar("case_status", state.phase || "investigation");
board.setVar("case_route", state.phase === "solved" ? "solved_chat" : "game_master");
board.setVar("case_progress_state_text", JSON.stringify(state, null, 2));

function latestUserText() {
  const msgs = board.channel(board.MAIN_CHANNEL) || [];
  for (let i = msgs.length - 1; i >= 0; i--) {
    const msg = msgs[i] || {};
    if (msg.role !== "user") continue;
    if (typeof msg.content === "string" && msg.content.trim()) return msg.content.trim();
    const parts = Array.isArray(msg.parts) ? msg.parts : [];
    const text = parts.map(function(part) {
      return part && part.type === "text" && typeof part.text === "string" ? part.text : "";
    }).join("").trim();
    if (text) return text;
  }
  return "";
}

function parseAction(line) {
  const text = String(line || "");
  const kind = (text.match(/kind=([^;\n]+)/) || text.match(/case_action:\s*([^;\n]+)/) || [])[1] || "other";
  const target = (text.match(/target=([^;\n]+)/) || [])[1] || "";
  return { kind: kind.trim(), target: target.trim() };
}

function addBadge(state, badge) {
  if (state.found.indexOf(badge) >= 0) return;
  state.found.push(badge);
  state.new_badges.push(badge);
}

function has(state, badge) {
  return state.found.indexOf(badge) >= 0;
}

function recommendedAction(nextScene) {
  if (nextScene === "study_lock") return { kind: "inspect_study_lock", target: "study_lock" };
  if (nextScene === "fireplace") return { kind: "inspect_fireplace", target: "fireplace" };
  if (nextScene === "gramophone") return { kind: "inspect_gramophone", target: "gramophone" };
  if (nextScene === "corridor") return { kind: "inspect_corridor", target: "back_corridor" };
  if (nextScene === "shen_zhiqiu_room") return { kind: "inspect_shen_zhiqiu_room", target: "shen_zhiqiu_room" };
  if (nextScene === "confrontation") return { kind: "accuse_shen_zhiqiu", target: "shen_zhiqiu" };
  return { kind: "ask_detail", target: nextScene || "case" };
}

function recompute(state) {
  const hasMethod = has(state, "found_thread_scratch") && has(state, "found_spare_key_compartment");
  const hasTime = has(state, "found_gramophone_loop");
  const hasRoute = has(state, "found_wet_footprints") || has(state, "noticed_wet_skirt");
  const hasMotive = has(state, "found_will_draft") || has(state, "found_old_newspaper");
  const missing = [];
  if (!hasMethod) missing.push("method");
  if (!hasTime) missing.push("time");
  if (!hasRoute) missing.push("route");
  if (!hasMotive) missing.push("motive");
  state.missing = missing;
  if (state.phase !== "solved") {
    state.phase = missing.length === 0 ? "accusation_ready" : "investigation";
  }
  if (state.phase === "solved") {
    state.next_scene = "epilogue";
  } else if (missing.indexOf("method") >= 0) {
    state.next_scene = has(state, "found_thread_scratch") ? "fireplace" : "study_lock";
  } else if (missing.indexOf("time") >= 0) {
    state.next_scene = "gramophone";
  } else if (missing.indexOf("route") >= 0) {
    state.next_scene = "corridor";
  } else if (missing.indexOf("motive") >= 0) {
    state.next_scene = "shen_zhiqiu_room";
  } else {
    state.next_scene = "confrontation";
  }
  state.recommended_action = recommendedAction(state.next_scene);
}

const state = Object.assign({
  phase: "investigation",
  found: [],
  missing: ["method", "time", "route", "motive"],
  next_scene: "study_lock",
  recommended_action: { kind: "inspect_study_lock", target: "study_lock" }
}, board.getVar("case_progress_state") || {});
state.found = Array.isArray(state.found) ? state.found : [];
state.new_badges = [];

const action = parseAction(board.getVar("case_action_text"));
const userText = latestUserText();
state.last_action = action.kind;
state.last_target = action.target;
state.latest_user_text = userText;
state.response_mode = "investigation";

if (action.kind === "start") {
  state.response_mode = "opening";
} else if (action.kind === "inspect_study_lock") {
  addBadge(state, "entered_study");
  addBadge(state, "inspected_door_lock");
  addBadge(state, "found_thread_scratch");
} else if (action.kind === "inspect_fireplace") {
  addBadge(state, "inspected_fireplace");
  addBadge(state, "found_spare_key_compartment");
} else if (action.kind === "inspect_gramophone") {
  addBadge(state, "inspected_gramophone");
  addBadge(state, "found_gramophone_loop");
} else if (action.kind === "inspect_corridor") {
  addBadge(state, "entered_back_corridor");
  addBadge(state, "found_wet_footprints");
} else if (action.kind === "inspect_shen_zhiqiu") {
  addBadge(state, "questioned_shen_zhiqiu");
  addBadge(state, "noticed_wet_skirt");
} else if (action.kind === "inspect_shen_zhiqiu_room") {
  addBadge(state, "questioned_shen_zhiqiu");
  addBadge(state, "noticed_wet_skirt");
  addBadge(state, "found_will_draft");
  addBadge(state, "found_old_newspaper");
} else if (action.kind === "accuse_shen_zhiqiu") {
  state.response_mode = "accusation";
} else if (action.kind === "ask_detail" && state.phase === "accusation_ready") {
  state.response_mode = "accusation";
} else {
  state.response_mode = "guidance";
}

recompute(state);
if ((action.kind === "accuse_shen_zhiqiu" || state.response_mode === "accusation") && state.phase === "accusation_ready") {
  state.phase = "solved";
  state.response_mode = "finale";
  addBadge(state, "accused_shen_zhiqiu");
  addBadge(state, "solved_case");
  recompute(state);
} else if (state.phase === "accusation_ready" && state.response_mode !== "finale") {
  state.response_mode = "ready";
}

board.setVar("case_progress_state", state);
board.setVar("case_status", state.phase);
board.setVar("case_action_kind", action.kind);
board.setVar("case_action_target", action.target);
board.setVar("case_progress_state_text", JSON.stringify(state, null, 2));

function latestUserText() {
  const msgs = board.channel(board.MAIN_CHANNEL) || [];
  for (let i = msgs.length - 1; i >= 0; i--) {
    const msg = msgs[i] || {};
    if (msg.role !== "user") continue;
    if (typeof msg.content === "string" && msg.content.trim()) return msg.content.trim();
    const parts = Array.isArray(msg.parts) ? msg.parts : [];
    const text = parts.map(function(part) {
      return part && part.type === "text" && typeof part.text === "string" ? part.text : "";
    }).join("").trim();
    if (text) return text;
  }
  return "";
}
board.setChannel("case_game_master_channel", [{
  role: "user",
  parts: [{ type: "text", text: latestUserText() }]
}]);

const state = board.getVar("case_progress_state") || {};
const phase = state.phase || "investigation";
const next = phase === "solved" ? "solved_chat" : "game_master";
const found = Array.isArray(state.found) ? state.found.slice().sort() : [];
const missing = Array.isArray(state.missing) && state.missing.length ? state.missing : [];
const nextLead = phase === "solved" ? "进入尾声闲聊。" :
  phase === "accusation_ready" ? "可以到大厅对质。" :
  state.next_scene === "study_lock" ? "继续查书房门锁和门缝。" :
  state.next_scene === "fireplace" ? "继续查壁炉暗格。" :
  state.next_scene === "gramophone" ? "检查留声机。" :
  state.next_scene === "corridor" ? "去后廊查看路线痕迹。" :
  state.next_scene === "shen_zhiqiu_room" ? "搜沈知秋房间抽屉找动机。" :
  "继续调查。";
board.setVar("tmp_case_state_line", "case_state: status=" + phase + "; next=" + next + "; next_scene=" + (state.next_scene || "") + ";");
board.setVar("tmp_progress_badges_line", "progress_badges: progress: phase=" + phase + "; found=" + found.join(",") + "; missing=" + (missing.length ? missing.join(",") : "none") + "; next=" + nextLead);
